<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Snake: Quantum Twist</title>
<style>
  body {
    margin: 0;
    background: #0f1220;
    color: #eaeaf0;
    font-family: Arial, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
  }
  canvas {
    background: #1b1f3a;
    margin-top: 20px;
    border-radius: 10px;
  }
  .ui {
    margin-top: 10px;
  }
  button {
    margin: 5px;
    padding: 8px 12px;
    border: none;
    border-radius: 6px;
    background: #4c6fff;
    color: white;
    cursor: pointer;
  }
</style>
</head>
<body>
<h2>Snake: Quantum Twist</h2>
<canvas id="game" width="500" height="500"></canvas>
<div class="ui">
  <span id="score">Score: 0</span>
  <button onclick="togglePortal()">Toggle Portals</button>
  <button onclick="restart()">Restart</button>
</div>

<script>
const canvas = document.getElementById("game");
const ctx = canvas.getContext("2d");
const grid = 20;
const tileCount = canvas.width / grid;

let snake, dir, food, score, speed, portalsEnabled, portals;

function init() {
  snake = [{x: 10, y: 10}];
  dir = {x: 1, y: 0};
  food = spawnFood();
  score = 0;
  speed = 120;
  portalsEnabled = false;
  portals = [spawnFood(), spawnFood()];
  document.getElementById("score").innerText = "Score: 0";
}

function spawnFood() {
  return {
    x: Math.floor(Math.random() * tileCount),
    y: Math.floor(Math.random() * tileCount)
  };
}

function gameLoop() {
  update();
  draw();
}

function update() {
  const head = {x: snake[0].x + dir.x, y: snake[0].y + dir.y};

  // Wrap around edges (twist 1)
  if (head.x < 0) head.x = tileCount - 1;
  if (head.x >= tileCount) head.x = 0;
  if (head.y < 0) head.y = tileCount - 1;
  if (head.y >= tileCount) head.y = 0;

  // Portal teleport (twist 2)
  if (portalsEnabled) {
    portals.forEach((p, i) => {
      if (head.x === p.x && head.y === p.y) {
        const other = portals[1 - i];
        head.x = other.x;
        head.y = other.y;
      }
    });
  }

  // Self collision = reverse instead of game over (twist 3)
  if (snake.some(s => s.x === head.x && s.y === head.y)) {
    snake.reverse();
    return;
  }

  snake.unshift(head);

  if (head.x === food.x && head.y === food.y) {
    score++;
    speed = Math.max(50, speed - 3); // speed up
    food = spawnFood();
    portals = [spawnFood(), spawnFood()];
    document.getElementById("score").innerText = "Score: " + score;
  } else {
    snake.pop();
  }
}

function draw() {
  ctx.fillStyle = "#1b1f3a";
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  // Draw snake
  ctx.fillStyle = "#6cf";
  snake.forEach(s => ctx.fillRect(s.x * grid, s.y * grid, grid - 2, grid - 2));

  // Draw food
  ctx.fillStyle = "#ff6b6b";
  ctx.fillRect(food.x * grid, food.y * grid, grid - 2, grid - 2);

  // Draw portals
  if (portalsEnabled) {
    ctx.fillStyle = "#9d4edd";
    portals.forEach(p => ctx.fillRect(p.x * grid, p.y * grid, grid - 2, grid - 2));
  }
}

window.addEventListener("keydown", e => {
  if (e.key === "ArrowUp" && dir.y === 0) dir = {x: 0, y: -1};
  if (e.key === "ArrowDown" && dir.y === 0) dir = {x: 0, y: 1};
  if (e.key === "ArrowLeft" && dir.x === 0) dir = {x: -1, y: 0};
  if (e.key === "ArrowRight" && dir.x === 0) dir = {x: 1, y: 0};
});

function togglePortal() {
  portalsEnabled = !portalsEnabled;
}

function restart() {
  init();
}

init();
setInterval(gameLoop, speed);
</script>
</body>
</html>
